// ═══════════════════════════════════════════════════════════════════════════
// Gráfico 2 — MSG Individual (Panel 2)
// Uma linha por característica • pico = variação entre medições • y: 0-1
// ═══════════════════════════════════════════════════════════════════════════

try {
  const panelData = context.panel.data;
  if (!panelData || !panelData.series || panelData.series.length === 0) {
    return { title: { text: 'Sem dados — selecione um repositório', left: 'center', top: 'center' } };
  }

  function toArr(field) {
    if (!field) return [];
    const v = field.values;
    if (!v) return [];
    if (v.buffer) return Array.from(new Float64Array(v.buffer));
    if (Array.isArray(v)) return v;
    if (typeof v.toArray === 'function') return v.toArray();
    return Array.from(v);
  }

  const frame = panelData.series[0];
  if (!frame || frame.fields.length === 0) {
    return { title: { text: 'Query sem retorno', left: 'center', top: 'center' } };
  }

  // ── Extração e Conversão de Datas ──────────────────────────────────────────
  const rawDatetimes = toArr(frame.fields.find(f => f.name === 'datetime'));
  const datetimes = rawDatetimes.map(ts => {
    const d = new Date(Number(ts));
    // Fallback de segurança caso a query retorne string em vez de timestamp
    if (isNaN(d.getTime())) return String(ts);

    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
  });

  const characteristics = [
    { key: 'reliability', label: 'Confiabilidade', color: '#00D9C9', data: toArr(frame.fields.find(f => f.name === 'reliability')) },
    { key: 'maintainability', label: 'Manutenibilidade', color: '#0080FF', data: toArr(frame.fields.find(f => f.name === 'maintainability')) },
    { key: 'functional_suitability', label: 'Adequação Funcional', color: '#FF6B35', data: toArr(frame.fields.find(f => f.name === 'functional_suitability')) },
  ];

  // ── Releases da query B ────────────────────────────────────────────────────
  // ── Releases da query B ────────────────────────────────────────────────────
  let releases = [];
  if (panelData.series.length > 1) {
    const rf = panelData.series[1];
    const rNames = toArr(rf.fields.find(f => f.name === 'release_name'));
    const rDates = toArr(rf.fields.find(f => f.name === 'release_date'));

    // Converter datetimes do eixo X para Epoch (ms) para garantir cálculo numérico seguro
    const datetimesMs = datetimes.map(d => new Date(d).getTime());
    const timeStart = datetimesMs[0];
    const timeEnd = datetimesMs[datetimesMs.length - 1];

    releases = rNames.reduce((acc, name, i) => {
      if (!name) return acc;

      const rawDate = rDates[i];
      let releaseDate = new Date(rawDate);

      // Fallback estrito caso o Grafana entregue a data como timestamp numérico
      if (isNaN(releaseDate.getTime()) && !isNaN(Number(rawDate))) {
        releaseDate = new Date(Number(rawDate));
      }

      const releaseTime = releaseDate.getTime();
      if (isNaN(releaseTime) || datetimesMs.length === 0) return acc;

      // Filtro arquitetural: Ignora releases que não pertencem ao intervalo atual do gráfico
      if (releaseTime < timeStart || releaseTime > timeEnd) {
        return acc;
      }

      // Localiza o índice da medição mais próxima através de menor delta de tempo absoluto
      let closestIdx = 0;
      let minDiff = Infinity;
      for (let j = 0; j < datetimesMs.length; j++) {
        const diff = Math.abs(datetimesMs[j] - releaseTime);
        if (diff < minDiff) {
          minDiff = diff;
          closestIdx = j;
        }
      }

      acc.push({ label: name, dateIndex: closestIdx });
      return acc;
    }, []);
  }
  // ── Função de pulso MSG ────────────────────────────────────────────────────
  function msgPulse(scores, idxList) {
    const SPS = 60;
    const pts = [];
    for (let ii = 0; ii < idxList.length - 1; ii++) {
      const a = scores[idxList[ii]] ?? 0, b = scores[idxList[ii + 1]] ?? 0;
      const delta = b - a, pk = delta * 2.2;
      for (let s = 0; s < SPS; s++) {
        const t = s / SPS;
        let v;
        if (t < 0.30) { v = a; }
        else if (t < 0.42) { const p = (t - 0.30) / 0.12; v = a + pk * Math.sin(p * Math.PI * 0.5); }
        else if (t < 0.56) { const p = (t - 0.42) / 0.14; v = a + pk * (1 - p); }
        else if (t < 0.68) { const p = (t - 0.56) / 0.12; v = b - delta * 0.15 * Math.sin(p * Math.PI); }
        else { v = b; }
        pts.push(Math.max(0.01, Math.min(0.99, v)));
      }
    }
    pts.push(Math.max(0.01, Math.min(0.99, scores[idxList[idxList.length - 1]] ?? 0)));
    return pts;
  }

  const N = datetimes.length;
  const idxList = Array.from({ length: N }, (_, i) => i);
  const SPS = 60;
  const nChars = characteristics.length;
  const isDark = context.grafana.theme.isDark;
  const textColor = isDark ? 'rgba(255,255,255,0.7)' : 'rgba(0,0,0,0.6)';
  const gridColor = isDark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)';

  // ── Layout: stat boxes à esquerda + gráficos à direita ────────────────────
  const topPad = 8, bottomPad = 10, gap = 4;
  const totalH = 100 - topPad - bottomPad;
  const rowH = (totalH - gap * (nChars - 1)) / nChars;

  const grids = characteristics.map((_, i) => ({
    top: `${topPad + i * (rowH + gap)}%`,
    height: `${rowH}%`,
    left: '120px',  // Espaço para stat boxes
    right: '20px',
  }));



  const xAxisData = [];
  if (N > 0) {
    for (let i = 0; i < N - 1; i++) {
      xAxisData.push(datetimes[i]); // Insere a data da aferição real
      for (let s = 1; s < SPS; s++) {
        xAxisData.push(''); // Preenche os pontos gerados pelo pulso com string vazia
      }
    }
    xAxisData.push(datetimes[N - 1]); // Insere a última aferição
  }

  const xAxes = characteristics.map((_, i) => ({
    type: 'category',
    gridIndex: i,
    data: xAxisData,
    axisLabel: {
      show: i === nChars - 1,  // Mostrar apenas no último gráfico
      color: textColor,
      fontSize: 10,
      // O ECharts permite usar uma função. Exibe a label APENAS se o valor não for vazio.
      interval: (index, value) => value !== '',
      formatter: (value) => {
        if (!value) return '';
        return String(value).slice(5, 10).replace('-', '/');
      }
    },
    axisLine: { lineStyle: { color: gridColor } },
    splitLine: { show: false },
    axisTick: {
      show: true,
      // Aplica a mesma regra da label: renderiza o tick apenas no índice da data real.
      interval: (index, value) => value !== '',
      length: 5
    }
  }));


  const yAxes = characteristics.map((c, i) => ({
    type: 'value',
    gridIndex: i,
    min: 0, max: 1,
    interval: 0.5,
    axisLabel: {
      color: textColor, fontSize: 8,
      formatter: v => v === 0 ? '0' : v === 0.5 ? '' : '1',
    },
    splitLine: { lineStyle: { color: gridColor } },
  }));

  const series = characteristics.map((c, i) => {
    // Cria as marcações dinamicamente para cada série
    const markLineData = releases.map(r => ({
      xAxis: r.dateIndex * SPS,
      label: {
        // Exibe o card APENAS no gráfico superior (índice 0)
        show: i === 0,
        formatter: r.label,
        position: 'end', // Coloca o card no topo da linha tracejada
        color: '#FFFFFF', // Cor do texto
        backgroundColor: '#BA7517', // Cor de fundo do card
        padding: [4, 8, 4, 8], // Espaçamento interno [topo, direita, base, esquerda]
        borderRadius: 4, // Arredondamento das bordas
        fontSize: 10,
        fontWeight: 'bold',
        distance: 5 // Distância entre o final da linha e o card
      },
      lineStyle: { color: '#BA7517', type: 'dashed', width: 1 },
    }));

    return {
      name: c.label,
      type: 'line',
      xAxisIndex: i,
      yAxisIndex: i,
      smooth: false,
      symbol: 'none',
      lineStyle: { color: c.color, width: 2 },
      data: msgPulse(c.data, idxList),
      markLine: {
        silent: true,
        symbol: ['none', 'none'], // Remove setas das pontas da linha
        data: markLineData,
      },
      markPoint: {
        symbol: 'circle', symbolSize: 8,
        data: releases.map(r => ({
          coord: [r.dateIndex * SPS, c.data[r.dateIndex] ?? 0],
          itemStyle: { color: c.color, borderColor: '#fff', borderWidth: 1 },
        })),
      },
    };
  });
  const mainTextColor = context.panel.isDark ? '#ffffff' : '#333333';
  // ── Stat boxes (gráficos customizados à esquerda) ─────────────────────────
  const statGraphics = characteristics.map((c, i) => {
    const lastValue = c.data[c.data.length - 1] ?? 0;
    const yPos = topPad + i * (rowH + gap);

    return {
      type: 'group',
      left: 10,
      top: `${yPos}%`,
      children: [
        // Nome da característica
        {
          type: 'text',
          left: 0,
          top: 0,
          style: {
            text: c.label,
            fontSize: 13,
            fontWeight: 'normal',
            fill: mainTextColor,
          },
        },
        // Valor grande
        {
          type: 'text',
          left: 0,
          top: 20,
          style: {
            text: lastValue.toFixed(2),
            fontSize: 24,
            fontWeight: 'bold',
            fill: c.color,
          },
        },
        // Label "último valor"
        {
          type: 'text',
          left: 0,
          top: 48,
          style: {
            text: 'último valor',
            fontSize: 9,
            fill: textColor,
          },
        },
      ],
    };
  });

  // ── Título e subtítulo ─────────────────────────────────────────────────────
  const titleGraphic = {
    type: 'group',
    left: 120,
    top: 0,
    children: [
      {
        type: 'text',
        left: 0,
        top: 0,
        style: {
          text: 'Gráfico 2 — MSG Individual',
          fontSize: 16,
          fontWeight: 'bold',
          fill: '#fff',
        },
      },
      {
        type: 'text',
        left: 0,
        top: 20,
        style: {
          text: 'Uma linha por característica • pico = variação entre medições • y: 0-1',
          fontSize: 11,
          fill: textColor,
        },
      },
    ],
  };

  // ── Rodapé com informações ─────────────────────────────────────────────────
  const lastDate = datetimes[datetimes.length - 1] || '';
  const repoName = context.grafana.replaceVariables('${repository:text}') || 'N/A';

  const footerGraphic = {
    type: 'text',
    left: 'center',
    bottom: 0,
    style: {
      text: `Repositório: ${repoName} · Última medição: ${lastDate} · ● = release`,
      fontSize: 10,
      fill: textColor,
    },
  };

  // ── Toolbox com exportação CSV ─────────────────────────────────────────────
  // Botão de export como graphic
  // Botão de export como graphic - VERSÃO MELHORADA
  // ── Toolbox com exportação CSV (FUNCIONAL) ─────────────────────────────────
  // Botão de export como graphic - VERSÃO MELHORADA
  // ── Toolbox com ícone de exportação ────────────────────────────────────────
  const toolbox = {
    show: true,
    feature: {
      myTool1: {
        show: true,
        title: 'Exportar CSV',
        icon: 'path://M14 2H6C4.89 2 4 2.9 4 4V20C4 21.11 4.89 22 6 22H18C19.11 22 20 21.11 20 20V8L14 2M18 20H6V4H13V9H18V20M12 19L8 15H10.5V12H13.5V15H16L12 19Z',
        onclick: function () {
          // Preparar dados CSV
          let csv = 'Data,Característica,Valor\n';

          characteristics.forEach(c => {
            c.data.forEach((val, idx) => {
              if (val !== null && val !== undefined) {
                const date = datetimes[idx];
                csv += `${date},${c.label},${val.toFixed(3)}\n`;
              }
            });
          });

          // Download do arquivo
          const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
          const link = document.createElement('a');
          const url = URL.createObjectURL(blob);
          const repoName = context.grafana.replaceVariables('${repository:text}') || 'repo';
          link.setAttribute('href', url);
          link.setAttribute('download', `msg_individual_${repoName}_${new
            Date().toISOString().split('T')[0]}.csv`);
          link.style.visibility = 'hidden';
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
        }
      }
    },
    right: 20,
    top: 5,
    itemSize: 18,
    itemGap: 10
  };




  return {
    backgroundColor: 'transparent',
    graphic: [titleGraphic, ...statGraphics, footerGraphic],
    tooltip: {
      trigger: 'axis',
      axisPointer: { type: 'line' },
      formatter: params => {
        const p = params[0];
        const charIdx = p.seriesIndex;
        const measureIdx = Math.min(Math.floor(p.dataIndex / SPS), N - 1);
        const c = characteristics[charIdx];
        const v = c.data[measureIdx] ?? 0;
        const prev = measureIdx > 0 ? (c.data[measureIdx - 1] ?? null) : null;
        const delta = prev !== null ? v - prev : null;
        const dt = datetimes[measureIdx];
        const rel = releases.find(r => r.dateIndex === measureIdx);
        let html = `<b>${dt}</b>`;
        if (rel) html += `<br/><span style="color:#BA7517">● ${rel.label}</span>`;
        html += `<br/><span style="color:${c.color}">■</span> ${c.label}: <b>${v.toFixed(2)}</b>`;
        if (delta !== null) {
          const col = delta >= 0 ? '#1D9E75' : '#E24B4A';
          html += ` <span style="color:${col}">${delta >= 0 ? '+' : ''}${delta.toFixed(2)}</span>`;
        }
        return html;
      },
    },
    toolbox,
    grid: grids,
    xAxis: xAxes,
    yAxis: yAxes,
    series,
  };
} catch (e) {
  return { title: { text: 'Erro: ' + e.message, left: 'center', top: 'center' } };
}
